    // Calculate deviance
    let deviance = y
        .iter()
        .zip(mu.iter())
        .map(|(&y_val, &mu_val)| (functions.dev_resid_fn)(y_val, mu_val))
        .sum();

    Ok(IrlsWorkingData {
