//! Performance validation benchmarks for CLAUDE.md targets
//!
//! This benchmark suite validates our performance targets:
//! - Linear Models: ≥2x faster than R's lm()
//! - Memory efficiency: ≤50% of R memory usage
//!
//! Uses simplified timing methodology for reliable CI integration

use criterion::{criterion_group, criterion_main, BenchmarkId, Criterion, Throughput};
use stats_models::Lm;
use std::time::Instant;

/// Generate deterministic test data for consistent benchmarking
fn generate_test_data(n_obs: usize, n_vars: usize) -> (Vec<f64>, Vec<f64>) {
    let mut x_data = Vec::with_capacity(n_obs * n_vars);
    let mut y_data = Vec::with_capacity(n_obs);

    for i in 0..n_obs {
        // Intercept column
        x_data.push(1.0);

        // Generate predictors with variation
        for j in 1..n_vars {
            x_data.push((i as f64 * j as f64 * 0.1).sin() + j as f64);
        }

        // Generate response with realistic noise
        let linear_part: f64 = (1..n_vars)
            .map(|j| x_data[i * n_vars + j] * (j as f64 * 0.5))
            .sum();
        let y = 2.0 + linear_part + (i as f64 * 0.01).cos() * 0.5;
        y_data.push(y);
    }

    (x_data, y_data)
}

/// Benchmark small models (target: demonstrate superiority)
fn bench_small_models(c: &mut Criterion) {
    let mut group = c.benchmark_group("small_models");

    for &n_vars in &[2, 3, 5] {
        let n_obs = 100;
        let (x_data, y_data) = generate_test_data(n_obs, n_vars);

        group.throughput(Throughput::Elements((n_obs * n_vars) as u64));
        group.bench_with_input(
            BenchmarkId::new("rust_lm", format!("{}x{}", n_obs, n_vars)),
            &(n_obs, n_vars),
            |b, _| {
                b.iter(|| {
                    let _fit = Lm::fit(&x_data, &y_data, n_obs, n_vars).unwrap();
                })
            },
        );
    }
    group.finish();
}

/// Benchmark medium models (target: 2x faster than R)
fn bench_medium_models(c: &mut Criterion) {
    let mut group = c.benchmark_group("medium_models");

    for &(n_obs, n_vars) in &[(500, 5), (1000, 10), (2000, 8)] {
        let (x_data, y_data) = generate_test_data(n_obs, n_vars);

        group.throughput(Throughput::Elements((n_obs * n_vars) as u64));
        group.bench_with_input(
            BenchmarkId::new("rust_lm", format!("{}x{}", n_obs, n_vars)),
            &(n_obs, n_vars),
            |b, _| {
                b.iter(|| {
                    let _fit = Lm::fit(&x_data, &y_data, n_obs, n_vars).unwrap();
                })
            },
        );
    }
    group.finish();
}

/// Benchmark large models (stress test)
fn bench_large_models(c: &mut Criterion) {
    let mut group = c.benchmark_group("large_models");
    group.sample_size(10); // Reduce samples for large data

    for &(n_obs, n_vars) in &[(5000, 10), (10000, 15)] {
        let (x_data, y_data) = generate_test_data(n_obs, n_vars);

        group.throughput(Throughput::Elements((n_obs * n_vars) as u64));
        group.bench_with_input(
            BenchmarkId::new("rust_lm", format!("{}x{}", n_obs, n_vars)),
            &(n_obs, n_vars),
            |b, _| {
                b.iter(|| {
                    let _fit = Lm::fit(&x_data, &y_data, n_obs, n_vars).unwrap();
                })
            },
        );
    }
    group.finish();
}

/// Performance regression guard - ensure we don't regress
fn bench_performance_regression(c: &mut Criterion) {
    // Standard dataset for tracking performance over time
    let (n_obs, n_vars) = (1000, 5);
    let (x_data, y_data) = generate_test_data(n_obs, n_vars);

    c.bench_function("regression_guard_1000x5", |b| {
        b.iter(|| {
            let _fit = Lm::fit(&x_data, &y_data, n_obs, n_vars).unwrap();
        })
    });
}

/// Memory allocation profiling (simplified)
fn bench_memory_efficiency(c: &mut Criterion) {
    let mut group = c.benchmark_group("memory_efficiency");

    for &(n_obs, n_vars) in &[(1000, 5), (5000, 10)] {
        let (x_data, y_data) = generate_test_data(n_obs, n_vars);

        group.bench_with_input(
            BenchmarkId::new("memory_profile", format!("{}x{}", n_obs, n_vars)),
            &(n_obs, n_vars),
            |b, _| {
                b.iter_custom(|iters| {
                    let start = Instant::now();
                    for _ in 0..iters {
                        let _fit = Lm::fit(&x_data, &y_data, n_obs, n_vars).unwrap();
                        // Force deallocation
                        std::hint::black_box(&_fit);
                    }
                    start.elapsed()
                })
            },
        );
    }
    group.finish();
}

criterion_group!(
    benches,
    bench_small_models,
    bench_medium_models,
    bench_large_models,
    bench_performance_regression,
    bench_memory_efficiency
);
criterion_main!(benches);

